40: /**
41:  * An interface for Authorizers which store state in the __cluster_metadata log.
42:  *
43:  * These methods must all be thread-safe.
44:  */
45: public interface ClusterMetadataAuthorizer extends Authorizer {
46:     /**
47:      * Set the mutator object which should be used for creating and deleting ACLs.
48:      */
49:     void setAclMutator(AclMutator aclMutator);
50: 
51:     /**
52:      * Get the mutator object which should be used for creating and deleting ACLs.
53:      *
54:      * @throws org.apache.kafka.common.errors.NotControllerException
55:      *              If the aclMutator was not set.
56:      */
57:     AclMutator aclMutatorOrException();
58: 
59:     /**
60:      * Complete the initial load of the cluster metadata authorizer, so that all
61:      * principals can use it.
62:      */
63:     void completeInitialLoad();
64: 
65:     /**
66:      * Complete the initial load of the cluster metadata authorizer with an exception,
67:      * indicating that the loading process has failed.
68:      */
69:     void completeInitialLoad(Exception e);
70: 
71:     /**
72:      * Load the ACLs in the given map. Anything not in the map will be removed.
73:      * The authorizer will also wait for this initial snapshot load to complete when
74:      * coming up.
75:      */
76:     void loadSnapshot(Map<Uuid, StandardAcl> acls);
77: 
78:     /**
79:      * Add a new ACL. Any ACL with the same ID will be replaced.
80:      */
81:     void addAcl(Uuid id, StandardAcl acl);
82: 
83:     /**
84:      * Remove the ACL with the given ID.
85:      */
86:     void removeAcl(Uuid id);
87: 
88:     /**
89:      * Create ACLs. This function must be called on the active controller, or else
90:      * the futures will fail with NOT_CONTROLLER.
91:      *
92:      * @param requestContext    The request context.
93:      * @param aclBindings       The ACL bindings to create.
94:      *
95:      * @return a list of futures, one per input acl binding. Each future will be completed
96:      * once addAcl has been called on the controller, and the ACL has been persisted to
97:      * the cluster metadata log.
98:      */
99:     default List<? extends CompletionStage<AclCreateResult>> createAcls(
100:             AuthorizableRequestContext requestContext,
101:             List<AclBinding> aclBindings) {
102:         List<CompletableFuture<AclCreateResult>> futures = new ArrayList<>(aclBindings.size());
103:         AclMutator aclMutator = aclMutatorOrException();
104:         aclBindings.forEach(b -> futures.add(new CompletableFuture<>()));
105:         ControllerRequestContext context = new ControllerRequestContext(
106:             requestContext, OptionalLong.empty());
107:         aclMutator.createAcls(context, aclBindings).whenComplete((results, throwable) -> {
108:             if (throwable == null && results.size() != futures.size()) {
109:                 throwable = new UnknownServerException("Invalid size " +
110:                     "of result set from controller. Expected " + futures.size() +
111:                     "; got " + results.size());
112:             }
113:             if (throwable == null) {
114:                 for (int i = 0; i < futures.size(); i++) {
115:                     futures.get(i).complete(results.get(i));
116:                 }
117:             } else {
118:                 for (CompletableFuture<AclCreateResult> future : futures) {
119:                     ApiException e = (throwable instanceof ApiException) ? (ApiException) throwable :
120:                         ApiError.fromThrowable(throwable).exception();
121:                     future.complete(new AclCreateResult(e));
122:                 }
123:             }
124:         });
125:         return futures;
126:     }
127: 
128:     /**
129:      * Delete ACLs based on filters. This function must be called on the active
130:      * controller, or else the futures will fail with NOT_CONTROLLER.
131:      *
132:      * @param requestContext    The request context.
133:      * @param filters           The ACL filters.
134:      *
135:      * @return a list of futures, one per input acl filter. Each future will be completed
136:      * once the relevant deleteAcls have been called on the controller (if any), and th
137:      * ACL deletions have been persisted to the cluster metadata log (if any).
138:      */
139:     default List<? extends CompletionStage<AclDeleteResult>> deleteAcls(
140:             AuthorizableRequestContext requestContext,
141:             List<AclBindingFilter> filters) {
142:         List<CompletableFuture<AclDeleteResult>> futures = new ArrayList<>(filters.size());
143:         AclMutator aclMutator = aclMutatorOrException();
144:         filters.forEach(b -> futures.add(new CompletableFuture<>()));
145:         ControllerRequestContext context = new ControllerRequestContext(
146:             requestContext, OptionalLong.empty());
147:         aclMutator.deleteAcls(context, filters).whenComplete((results, throwable) -> {
148:             if (throwable == null && results.size() != futures.size()) {
149:                 throwable = new UnknownServerException("Invalid size " +
150:                     "of result set from controller. Expected " + futures.size() +
151:                     "; got " + results.size());
152:             }
153:             if (throwable == null) {
154:                 for (int i = 0; i < futures.size(); i++) {
155:                     futures.get(i).complete(results.get(i));
156:                 }
157:             } else {
158:                 for (CompletableFuture<AclDeleteResult> future : futures) {
159:                     ApiException e = (throwable instanceof ApiException) ? (ApiException) throwable :
160:                         ApiError.fromThrowable(throwable).exception();
161:                     future.complete(new AclDeleteResult(e));
162:                 }
163:             }
164:         });
165:         return futures;
166:     }
167: }
