35: public class AclPublisher implements MetadataPublisher {
36:     private final Logger log;
37:     private final int nodeId;
38:     private final FaultHandler faultHandler;
39:     private final String nodeType;
40:     private final Optional<Plugin<Authorizer>> authorizer;
41:     private boolean completedInitialLoad = false;
42: 
43:     public AclPublisher(int nodeId, FaultHandler faultHandler, String nodeType, Optional<Plugin<Authorizer>> authorizer) {
44:         this.nodeId = nodeId;
45:         this.faultHandler = faultHandler;
46:         this.nodeType = nodeType;
47:         this.authorizer = authorizer.filter(plugin -> plugin.get() instanceof ClusterMetadataAuthorizer);
48:         this.log = new LogContext(name()).logger(AclPublisher.class);
49:     }
50: 
51:     @Override
52:     public final String name() {
53:         return "AclPublisher " + nodeType + " id=" + nodeId;
54:     }
55: 
56:     @Override
57:     public void onMetadataUpdate(MetadataDelta delta, MetadataImage newImage, LoaderManifest manifest) {
58:         String deltaName = "MetadataDelta up to " + newImage.offset();
59: 
60:         // Apply changes to ACLs. This needs to be handled carefully because while we are
61:         // applying these changes, the Authorizer is continuing to return authorization
62:         // results in other threads. We never want to expose an invalid state. For example,
63:         // if the user created a DENY ALL acl and then created an ALLOW ACL for topic foo,
64:         // we want to apply those changes in that order, not the reverse order! Otherwise
65:         // there could be a window during which incorrect authorization results are returned.
66:         Optional.ofNullable(delta.aclsDelta()).ifPresent(aclsDelta -> {
67:             authorizer.ifPresent(authorizer -> {
68:                 ClusterMetadataAuthorizer clusterMetadataAuthorizer = (ClusterMetadataAuthorizer) authorizer.get();
69:                 if (manifest.type().equals(LoaderManifestType.SNAPSHOT)) {
70:                     try {
71:                         // If the delta resulted from a snapshot load, we want to apply the new changes
72:                         // all at once using ClusterMetadataAuthorizer#loadSnapshot. If this is the
73:                         // first snapshot load, it will also complete the futures returned by
74:                         // Authorizer#start (which we wait for before processing RPCs).
75:                         log.info("Loading authorizer snapshot at offset {}", newImage.offset());
76:                         clusterMetadataAuthorizer.loadSnapshot(newImage.acls().acls());
77:                     } catch (Throwable t) {
78:                         faultHandler.handleFault("Error loading authorizer snapshot in " + deltaName, t);
79:                     }
80:                 } else {
81:                     try {
82:                         // Because the changes map is a LinkedHashMap, the deltas will be returned in
83:                         // the order they were performed.
84:                         aclsDelta.changes().forEach((key, value) -> {
85:                             if (value.isPresent()) {
86:                                 clusterMetadataAuthorizer.addAcl(key, value.get());
87:                             } else {
88:                                 clusterMetadataAuthorizer.removeAcl(key);
89:                             }
90:                         });
91:                     } catch (Throwable t) {
92:                         faultHandler.handleFault("Error loading authorizer changes in " + deltaName, t);
93:                     }
94:                 }
95:                 if (!completedInitialLoad) {
96:                     // If we are receiving this onMetadataUpdate call, that means the MetadataLoader has
97:                     // loaded up to the local high water mark. So we complete the initial load, enabling
98:                     // the authorizer.
99:                     completedInitialLoad = true;
100:                     clusterMetadataAuthorizer.completeInitialLoad();
